    for (int i = 2; i <= n; i++) {
        long temp = a + b;
        a = b;
        b = temp;
    }
    memo.put(n, b);
    return b;
}","codeSnippetDiff":"+ private final Map<Integer, Long> memo = new HashMap<>();
